        if (lazy[v] == 0) return;
        int mid = (l + r) >> 1;
        tree[v << 1] += lazy[v];
        lazy[v << 1] += lazy[v];
        tree[v << 1 | 1] += lazy[v];
        lazy[v << 1 | 1] += lazy[v];
        lazy[v] = 0;
    }

