        if (qr < l || ql > r) return 0;
        if (ql <= l && r <= qr) return tree[v];
        push(v, l, r);
        int mid = (l + r) >> 1;
        return max(queryMax(v << 1, l, mid, ql, qr),
                   queryMax(v << 1 | 1, mid + 1, r, ql, qr));
    }

    void updateRange(int v, int l, int r, int ql, int qr, long long val) {
        if (qr < l || ql > r) return;
        if (ql <= l && r <= qr) {
            tree[v] += val;
            lazy[v] += val;
            return;
        }
        push(v, l, r);
        int mid = (l + r) >> 1;
        updateRange(v << 1, l, mid, ql, qr, val);
        updateRange(v << 1 | 1, mid + 1, r, ql, qr, val);
        tree[v] = max(tree[v << 1], tree[v << 1 | 1]);
    }

    long long querySum(int v, int l, int r, int ql, int qr) {
        if (qr < l || ql > r) return 0;
        if (ql <= l && r <= qr) return tree[v];
        push(v, l, r);
        int mid = (l + r) >> 1;
        return querySum(v << 1, l, mid, ql, qr) +
               querySum(v << 1 | 1, mid + 1, r, ql, qr);
    }

    int findFirstRow(int v, int l, int r, int ql, int qr, int k) {
        if (qr < l || ql > r || tree[v] < k) return -1;
        if (l == r) return l;
        push(v, l, r);
        int mid = (l + r) >> 1;
        int left = findFirstRow(v << 1, l, mid, ql, qr, k);
        if (left != -1) return left;
        return findFirstRow(v << 1 | 1, mid + 1, r, ql, qr, k);
    }

public:
    BookMyShow(int n, int m) : n(n), m(m) {
        tree.resize(4 * n);
        lazy.resize(4 * n);
        rowStart.resize(n, 0);
        build(1, 0, n - 1);
    }

    vector<int> gather(int k, int maxRow) {
        int r = findFirstRow(1, 0, n - 1, 0, maxRow, k);
        if (r == -1) return {};
        int c = rowStart[r];
        updateRange(1, 0, n - 1, r, r, -k);
        rowStart[r] += k;
        return {r, c};
    }

    bool scatter(int k, int maxRow) {
        long long total = querySum(1, 0, n - 1, 0, maxRow);
        if (total < k) return false;
        int left = k;
        for (int r = 0; r <= maxRow && left > 0; ++r) {
            long long avail = m - rowStart[r];
            if (avail <= 0) continue;
            long long take = min((long long)left, avail);
            updateRange(1, 0, n - 1, r, r, -take);
            rowStart[r] += take;
            left -= take;
        }
        return true;
    }
};
